        var items = [];
        // 增加超时处理，防止被弹窗卡死
        var html = request(input);

        // 调试代码：如果列表为空，尝试从整个页面抓取所有 a 标签
        var cards = pdfa(html, '.cardBox, .section-content__item, .swiper-slide');

        if (cards.length === 0) {
            // 如果按照类名抓不到，说明页面可能被拦截或结构变化，尝试暴力抓取带 archives 的链接
            var links = pdfa(html, 'a[href*="archives"]');
            links.forEach(function(it) {
                var title = pdfh(it, '&&Text') || '精彩视频';
                var img = pd(it, 'img&&data-src') || pd(it, 'img&&src');
                if (img) {
                    items.push({
                        title: title.trim(),
                        img: img,
                        url: pd(it, '&&href')
                    });
                }
            });
        } else {
            cards.forEach(function(it) {
                var title = pdfh(it, '.cardTitle&&Text') || pdfh(it, 'a&&aria-label') || pdfh(it, 'img&&alt');
                var img = pd(it, 'img&&data-src') || pd(it, 'img&&data-src-pc') || pd(it, 'img&&src');
                if (title && img) {
                    items.push({
                        title: title,
                        img: img,
                        desc: pdfh(it, '.cardTag&&Text') || 'HD',
                        url: pd(it, 'a&&href')
                    });
                }
            });
        }
        setResult(items);

