js:
        var html = request(input);
        var pathMatch = html.match(/const\s+path\s*=\s*"(.*?)"/);
        if (pathMatch) {
            var path = pathMatch[1].replace(/\\u0026/g, '&');
            input = { jx: 0, url: 'https://madou.com/h5/m3u8/' + path, parse: 0 };
        } else {
            input = { jx: 0, url: input, parse: 1 };
        }
